out.write('function createTables(): void {\n')
out.write("  if (!db) throw new Error('Database not initialized');\n")
out.write('  db.run(`CREATE TABLE IF NOT EXISTS users (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    username TEXT UNIQUE NOT NULL,\n    password_hash TEXT NOT NULL,\n    display_name TEXT NOT NULL,\n    role TEXT DEFAULT \'user\' CHECK(role IN (\'user\', \'admin\')),\n    login_attempts INTEGER DEFAULT 0,\n    locked_until DATETIME,\n    last_login DATETIME,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n  )`);\n')
out.write('  db.run(`CREATE TABLE IF NOT EXISTS projects (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    name TEXT NOT NULL, description TEXT, password_hash TEXT,\n    failed_attempts INTEGER DEFAULT 0, locked_until DATETIME,\n    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, deleted_at DATETIME\n  )`);\n')
out.write('  db.run(`CREATE TABLE IF NOT EXISTS documents (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    project_id INTEGER NOT NULL REFERENCES projects(id) ON DELETE CASCADE,\n    name TEXT NOT NULL, original_filename TEXT NOT NULL,\n    file_path TEXT NOT NULL, file_type TEXT NOT NULL,\n    file_size INTEGER NOT NULL DEFAULT 0,\n    status TEXT DEFAULT \'pending\' CHECK(status IN (\'pending\',\'processing\',\'completed\',\'failed\')),\n    error_message TEXT,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, deleted_at DATETIME\n  )`);\n')
out.write('  db.run(`CREATE TABLE IF NOT EXISTS clauses (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    document_id INTEGER NOT NULL REFERENCES documents(id) ON DELETE CASCADE,\n    clause_number TEXT NOT NULL, title TEXT, content TEXT NOT NULL,\n    level INTEGER DEFAULT 1, parent_id INTEGER REFERENCES clauses(id),\n    order_index INTEGER DEFAULT 0, page_number INTEGER,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n  )`);\n')
out.write('  db.run(`CREATE TABLE IF NOT EXISTS risk_rules (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    name TEXT NOT NULL,\n    category TEXT NOT NULL DEFAULT \'' + '\u5176\u4ed6' + '\',\n    description TEXT,\n    risk_level TEXT NOT NULL CHECK(risk_level IN (\'high\',\'medium\',\'low\')),\n    keywords TEXT NOT NULL DEFAULT \'[]\',\n    pattern TEXT,\n    is_enabled INTEGER NOT NULL DEFAULT 1,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n  )`);\n')
out.write('  db.run(`CREATE TABLE IF NOT EXISTS risk_matches (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    clause_id INTEGER NOT NULL REFERENCES clauses(id) ON DELETE CASCADE,\n    rule_id INTEGER NOT NULL REFERENCES risk_rules(id),\n    risk_level TEXT NOT NULL CHECK(risk_level IN (\'high\',\'medium\',\'low\')),\n    matched_text TEXT NOT NULL, suggestion TEXT,\n    user_adjusted_level TEXT CHECK(user_adjusted_level IN (\'high\',\'medium\',\'low\')),\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP\n  )`);\n')
out.write('  db.run(`CREATE TABLE IF NOT EXISTS annotations (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    clause_id INTEGER NOT NULL REFERENCES clauses(id) ON DELETE CASCADE,\n    user_id INTEGER NOT NULL REFERENCES users(id),\n    type TEXT NOT NULL CHECK(type IN (\'comment\',\'suggestion\',\'question\',\'issue\')),\n    content TEXT NOT NULL,\n    status TEXT DEFAULT \'active\' CHECK(status IN (\'active\',\'resolved\',\'deleted\')),\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n  )`);\n')
out.write('  db.run(`CREATE TABLE IF NOT EXISTS document_versions (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    document_id INTEGER NOT NULL REFERENCES documents(id) ON DELETE CASCADE,\n    version_number INTEGER NOT NULL, content TEXT NOT NULL,\n    created_by INTEGER NOT NULL REFERENCES users(id),\n    comment TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n    UNIQUE(document_id, version_number)\n  )`);\n')
out.write('  db.run(`CREATE TABLE IF NOT EXISTS audit_logs (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    user_id INTEGER NOT NULL REFERENCES users(id),\n    action TEXT NOT NULL, resource_type TEXT NOT NULL,\n    resource_id INTEGER, details TEXT, ip_address TEXT,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP\n  )`);\n')
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_users_username ON users(username)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_projects_user_id ON projects(user_id)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_documents_project ON documents(project_id)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_documents_status ON documents(status)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_clauses_document ON clauses(document_id)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_risk_matches_clause ON risk_matches(clause_id)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_risk_matches_level ON risk_matches(risk_level)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_annotations_clause ON annotations(clause_id)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_annotations_user ON annotations(user_id)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_annotations_status ON annotations(status)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_document_versions_document ON document_versions(document_id)');\n")
out.write("  db.run('CREATE INDEX IF NOT EXISTS idx_audit_logs_user ON audit_logs(user_id)');\n")
out.write('}\n\n')
out.close()
print('tables done')
